final:
module top_module(
  input wire clk,
  input wire reset,
  input wire [7:0] obf_bin,
  output reg [7:0] gray
);always @(posedge clk, posedge reset) begin
    if (reset) begin
      gray <= 8'b0;
    end else begin
      gray[7] <= obf_bin[7];
      gray[6] <= obf_bin[7] ^ obf_bin[6];
      gray[5] <= obf_bin[6] ^ obf_bin[5];
      gray[4] <= obf_bin[5] ^ obf_bin[4];
      gray[3] <= obf_bin[4] ^ obf_bin[3];
      gray[2] <= obf_bin[3] ^ obf_bin[2];
      gray[1] <= obf_bin[2] ^ obf_bin[1];
      gray[0] <= obf_bin[1] ^ obf_bin[0];
    end
  end

endmodule
